 10→# ── Helper: create mock directory trees for testing ──────────────────────────
 11→function New-MockDirectoryTree {
 12→    <#
 13→    .SYNOPSIS
 14→        Creates a temporary directory tree from a hashtable specification.
 15→        Keys are relative file paths, values are file content strings.
 16→    #>
 17→    param(
 18→        [hashtable]$Files
 19→    )
 20→    $root = Join-Path ([System.IO.Path]::GetTempPath()) "dts-test-$([guid]::NewGuid().ToString('N').Substring(0,8))"
 21→    New-Item -ItemType Directory -Path $root -Force | Out-Null
 22→
 23→    foreach ($relPath in $Files.Keys) {
 24→        $fullPath = Join-Path $root $relPath
 25→        $dir = Split-Path $fullPath -Parent
 26→        if (-not (Test-Path $dir)) {
 27→            New-Item -ItemType Directory -Path $dir -Force | Out-Null
 28→        }
 29→        Set-Content -Path $fullPath -Value $Files[$relPath] -NoNewline
 30→    }
 31→    return $root
 32→}
