 63→                [Text.Encoding]::UTF8.GetBytes('same content')
 64→            )) -Algorithm SHA256).Hash
 65→            $normalizedKey = ($map.Keys | Where-Object { $_ -match 'x\.txt$' }) | Select-Object -First 1
 66→            $map[$normalizedKey] | Should -Be $expected
