353→# ══════════════════════════════════════════════════════════════════════════════
354→# TDD Cycle 6: Full end-to-end sync scenario
355→# ══════════════════════════════════════════════════════════════════════════════
356→Describe 'End-to-end sync' {
357→
358→    It 'makes the target tree identical to the source tree' {
359→        $source = New-MockDirectoryTree @{
360→            'readme.md'       = '# Project'
361→            'src/main.ps1'    = 'Write-Host "Hello"'
362→            'src/lib/util.ps1'= 'function foo {}'
363→        }
364→        $target = New-MockDirectoryTree @{
365→            'readme.md'       = '# Old Readme'
366→            'obsolete.txt'    = 'should be removed'
367→        }
368→        try {
369→            # Generate and execute the sync plan
370→            $plan = New-SyncPlan -SourcePath $source -TargetPath $target
371→            Invoke-SyncPlan -Plan $plan -SourcePath $source -TargetPath $target -Execute
372→
373→            # After sync, the target should match the source
374→            $sourceMap = Get-FileHashMap -Path $source
375→            $targetMap = Get-FileHashMap -Path $target
376→
377→            $sourceMap.Keys.Count | Should -Be $targetMap.Keys.Count
378→
379→            foreach ($key in $sourceMap.Keys) {
380→                $targetMap.ContainsKey($key) | Should -BeTrue -Because "target should contain $key"
381→                $targetMap[$key] | Should -Be $sourceMap[$key] -Because "hash of $key should match"
382→            }
383→
384→            # Obsolete file should be gone
385→            Test-Path (Join-Path $target 'obsolete.txt') | Should -BeFalse
386→        } finally {
387→            Remove-Item $source -Recurse -Force
388→            Remove-Item $target -Recurse -Force
389→        }
390→    }
391→
392→    It 'dry-run followed by execute produces expected results' {
393→        $source = New-MockDirectoryTree @{
394→            'a.txt' = 'alpha'
395→            'b.txt' = 'beta'
396→        }
397→        $target = New-MockDirectoryTree @{
398→            'a.txt' = 'alpha-old'
399→            'c.txt' = 'charlie'
400→        }
401→        try {
402→            $plan = New-SyncPlan -SourcePath $source -TargetPath $target
403→
404→            # Dry run first - should report 3 actions (overwrite a.txt, copy b.txt, delete c.txt)
405→            $dryReport = Invoke-SyncPlan -Plan $plan -SourcePath $source -TargetPath $target -DryRun
406→            @($dryReport).Count | Should -Be 3
407→
408→            # Target unchanged after dry run
409→            (Get-Content (Join-Path $target 'a.txt') -Raw) | Should -Be 'alpha-old'
410→            Test-Path (Join-Path $target 'c.txt') | Should -BeTrue
411→
412→            # Now execute
413→            # Need a fresh plan since the state hasn't changed
414→            Invoke-SyncPlan -Plan $plan -SourcePath $source -TargetPath $target -Execute
415→
416→            # Target now matches source
417→            (Get-Content (Join-Path $target 'a.txt') -Raw) | Should -Be 'alpha'
418→            (Get-Content (Join-Path $target 'b.txt') -Raw) | Should -Be 'beta'
419→            Test-Path (Join-Path $target 'c.txt') | Should -BeFalse
420→        } finally {
421→            Remove-Item $source -Recurse -Force
422→            Remove-Item $target -Recurse -Force
423→        }
424→    }
425→}
426→
